<?php require_once 'config/auth.php'; require_login(); require_once 'config/db.php'; include 'header.php'; if(is_admin()){$stmt=$pdo->query('SELECT b.*,u.name,e.title FROM bookings b JOIN users u ON b.user_id=u.id JOIN events e ON b.event_id=e.id ORDER BY b.created_at DESC');}else{$stmt=$pdo->prepare('SELECT b.*,u.name,e.title FROM bookings b JOIN users u ON b.user_id=u.id JOIN events e ON b.event_id=e.id WHERE b.user_id=? ORDER BY b.created_at DESC');$stmt->execute([$_SESSION['user_id']]);} $rows=$stmt->fetchAll(PDO::FETCH_ASSOC); ?><h1>Booking Records</h1><table class="table"><tr><th>User</th><th>Event</th><th>Tickets</th><th>Total</th><th>Status</th><th>Date</th></tr><?php foreach($rows as $r): ?><tr><td><?php echo e($r['name']); ?></td><td><?php echo e($r['title']); ?></td><td><?php echo e($r['tickets']); ?></td><td>$<?php echo e($r['total_price']); ?></td><td><span class="badge badge-open"><?php echo e($r['status']); ?></span></td><td><?php echo e($r['created_at']); ?></td></tr><?php endforeach; ?></table><?php include 'footer.php'; ?>